VALUES
  ('police-b20a8cf8-moex-00184', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', 'DNA 分析鑑定時，遇到生物檢體過於微量，而無法被檢出足資比對之 DNA-STR 型別時；此時 可針對微量DNA採取適當之訊號增強或訊號處理方法，請問下列方法何者最不適當？', '["濃縮DNA", "降低DNA-STR圖譜分析訊號強度（peak）之研判標準", "增加PCR複製之循環數（cycle）", "增加毛細管電泳分析之電磁導注（electrokineticinjection）時間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00185', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '在DNA分析鑑定中，下列那些常見抑制物會影響PCR反應？①血紅素  ②檳榔渣  ③人類', '["牛仔布之色素  ⑤腐植酸", "", "", "⑤"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00186', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關槍擊案現場重建與研判問題，下列敘述何者最不適當？', '["由現場遺留之彈殼原始位置，大略可研判射擊該子彈槍手的射擊位置", "由人體槍傷傷口周緣留有之擦傷環，可研判應為射入口", "由射擊後彈頭上陽線及陰線旋轉方向及纏角角度，可研判該子彈係由那一支槍所射", "由玻璃被子彈射過之口緣直徑大小，可研判玻璃那一側為射入口"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00187', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以X-射線檢測技術檢測隱藏爆炸物，下列關於其原理與技術之敘述何者最不適當？', '["所有X-射線爆炸物檢測儀器均以檢測穿透或散射X-射線形成之影像為研判依據", "X-射線穿透檢測以掃描方式進行檢測，檢測穿透之X-射線訊號，可檢出含金屬物品，無法檢 出有機爆炸物", "X-射線係原子的外層軌域電子掉入空的內層電子軌域時，而發射出的電磁波，其能量恰等於 兩電子軌域的能階差", "高原子序元素組成的物體，X-射線穿透影像之反差極弱，不易辨識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00188', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '利用光學原理來增顯指紋影像或減弱背景干擾，可以使得指紋紋線特徵更加清晰。請問以寧海得 林法顯現之指紋，若其顯現出來的指紋顏色較淡，此時可以選擇何種色光進行照射，使得指紋紋 線顏色變深？', '["紫色光", "橙色光", "綠色光", "藍色光"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00189', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '在詐欺集團處所查扣國內多家銀行支票，為對支票進行最佳化指紋採證，考慮應用相關指紋採取', '["目視及多波域光源檢查", "紅外線反射攝影", "寧海得林法", "1,2茚滿二酮法（1,2- Indandione）  ⑤物理顯影法時；請問依上述方法採取何種步驟次序為最適當之系統化步驟？"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00190', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '近年來大麻毒品在國內濫用情形有增加趨勢，為增進查緝與鑑定效能，有關大麻毒品外觀特徵、 成分含量、快速檢測方法及吸食代謝等敘述，下列何者錯誤？', '["大麻為雌雄異株，葉子呈掌狀複葉，各小葉為狹鋸針形，邊緣有粗鋸齒，葉上覆有爪狀茸毛", "大麻主要係含有四氫大麻酚（THC），具有迷幻藥性質；莖及種子含量較高，花及葉子含量甚微", "吸食大麻幾分鐘後就可在血漿中偵測到THC的代謝物9-THC-COOH", "以Duquenois試劑呈色法檢測大麻，陽性反應為藍紫色"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00191', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '射擊殘跡的顆粒分析一般是以電子顯微鏡來分析射擊殘跡之顆粒形狀與大小，並以 X 射線能譜', '["成分", "形 狀", "直徑大小），何者最可判定為射擊殘跡？", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00192', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為檢測送鑑定之空氣槍殺傷力，經量測所使用之彈丸尺寸直徑為6 mm，質量為0.88 g，測試其 發射速度為70公尺/秒，請計算該槍枝發射之單位面積動能？', '["7.6焦耳/平方公分", "15.3焦耳/平方公分", "21.6焦耳/平方公分", "271.8焦耳/平方公分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00193', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為顯現刑案現場中①疑似嫌犯遺留的寶特瓶  ②觸摸的櫥櫃玻璃  ③浸水的凶器  ④涉案汽車 內部留滯的塑膠袋等物體上之潛伏指紋，分別以何種指紋採驗法採取較佳？', '["", "金屬鍍膜法", "粉末法", "氰丙烯酸酯法"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
